/**
 * @name SpEL injection in WhitelabelErrorEndpoint via error_message attribute
 * @description User-controlled error message flows into SpEL template evaluation in WhitelabelErrorEndpoint
 * @kind path-problem
 * @problem.severity error
 * @id java/spel-injection-whitelabel-error
 * @tags security
 *       external/cwe/cwe-917
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module SpelWhitelabelConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: anything put into a ModelAndView/Map model in WhitelabelErrorEndpoint or WhitelabelApprovalEndpoint
    exists(MethodCall mc |
      mc.getMethod().hasName("addAttribute") or
      mc.getMethod().hasName("put") |
      sink.asExpr() = mc.getAnArgument() and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName(
        "org.springframework.security.oauth2.provider.endpoint", "WhitelabelErrorEndpoint"
      )
    )
  }
}

module SpelWhitelabelFlow = TaintTracking::Global<SpelWhitelabelConfig>;
import SpelWhitelabelFlow::PathGraph

from SpelWhitelabelFlow::PathNode source, SpelWhitelabelFlow::PathNode sink
where SpelWhitelabelFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User input flows into SpelView model in WhitelabelErrorEndpoint from $@.", source.getNode(), "user input"

/**
 * @name Unsafe deserialization - SerializationUtils with tainted input
 * @description Traces data flow from network sources to ObjectInputStream.readObject() in SerializationUtils
 * @kind path-problem
 * @problem.severity error
 * @id java/unsafe-deserialization-tainted
 * @tags security
 *       external/cwe/cwe-502
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module DeserializationConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: calls to SerializationUtils.deserialize
    exists(MethodCall mc |
      mc.getMethod().hasName("deserialize") and
      mc.getMethod().getDeclaringType().hasQualifiedName(
        "org.springframework.security.oauth2.common.util", "SerializationUtils"
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Also direct readObject on ObjectInputStream
    exists(MethodCall mc |
      mc.getMethod().hasName("readObject") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "ObjectInputStream") and
      sink.asExpr() = mc.getQualifier()
    )
  }
}

module DeserializationFlow = TaintTracking::Global<DeserializationConfig>;
import DeserializationFlow::PathGraph

from DeserializationFlow::PathNode source, DeserializationFlow::PathNode sink
where DeserializationFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Untrusted data flows to deserialization from $@.", source.getNode(), "user input"

/**
 * @name WhitelabelErrorEndpoint: request attribute flows into SpEL model (local flow)
 * @description Check if request attributes flow to the SpEL model map in WhitelabelErrorEndpoint
 * @kind path-problem
 * @problem.severity error
 * @id java/whitelabel-error-local-flow
 * @tags security
 *       external/cwe/cwe-917
 */

import java
import semmle.code.java.dataflow.TaintTracking

module SpelErrorLocalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getAttribute") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet", "ServletRequest") and
      source.asExpr() = mc and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName(
        "org.springframework.security.oauth2.provider.endpoint", "WhitelabelErrorEndpoint"
      )
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("put") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName(
        "org.springframework.security.oauth2.provider.endpoint", "WhitelabelErrorEndpoint"
      ) and
      sink.asExpr() = mc.getArgument(1)
    )
  }
}

module SpelErrorLocalFlow = TaintTracking::Global<SpelErrorLocalConfig>;
import SpelErrorLocalFlow::PathGraph

from SpelErrorLocalFlow::PathNode source, SpelErrorLocalFlow::PathNode sink
where SpelErrorLocalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Request attribute flows into SpEL model from $@.", source.getNode(), "request.getAttribute"

/**
 * @name WhitelabelApprovalEndpoint: request parameter flows into SpEL template model
 * @description User-controlled OAuth scope/client_id in approval endpoint flows to SpEL model
 * @kind path-problem
 * @problem.severity error
 * @id java/whitelabel-approval-spel
 * @tags security
 *       external/cwe/cwe-917
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module SpelApprovalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      (mc.getMethod().hasName("put") or mc.getMethod().hasName("addAttribute")) and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName(
        "org.springframework.security.oauth2.provider.endpoint", "WhitelabelApprovalEndpoint"
      ) and
      sink.asExpr() = mc.getArgument(1)
    )
  }
}

module SpelApprovalFlow = TaintTracking::Global<SpelApprovalConfig>;
import SpelApprovalFlow::PathGraph

from SpelApprovalFlow::PathNode source, SpelApprovalFlow::PathNode sink
where SpelApprovalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User input flows into SpEL approval model from $@.", source.getNode(), "user input"
